{
  "__faion_header__": {
    "methodology": "testing-with-assistive-technology",
    "version": "1.1.0",
    "produces": "config"
  },
  "tiers": {
    "automated_ci": {
      "tools": [
        "axe-core",
        "lighthouse"
      ],
      "fail_on_new_violations": true,
      "owner": "fe-team"
    },
    "manual_release": {
      "screen_readers": [
        "voiceover",
        "nvda"
      ],
      "keyboard_only": true,
      "owner": "qa-lead"
    },
    "at_user_quarterly": {
      "partner": "AbilityTech Research",
      "users_per_quarter": 2,
      "owner": "a11y-lead"
    }
  },
  "bug_report_format": {
    "wcag_sc": true,
    "repro": true,
    "apg_pattern": true,
    "scope": true
  }
}
